using System; using System.Runtime.InteropServices; using System.Threading; using System.Threading.Tasks; using Microsoft.FlightSimulator.SimConnect; namespace SimConnectTester { class Program { static SimConnect? simconnect = null; static bool isRunning = true; static async Task Main(string[] args) { Console.WriteLine(">> Starting SimConnect Connection Test..."); try { simconnect = new SimConnect("Tester", IntPtr.Zero, 0, null, 0); Console.WriteLine(">> new SimConnect() returned! Natively connected to pipe."); simconnect.OnRecvOpen += (s, e) => { Console.WriteLine(">> OnRecvOpen FIRE! Connection officially established."); }; simconnect.OnRecvQuit += (s, e) => { Console.WriteLine(">> OnRecvQuit FIRE! Simulator closed."); isRunning = false; }; simconnect.OnRecvException += (s, e) => { Console.WriteLine(">> OnRecvException FIRE! Error: " + e.dwException); }; Console.WriteLine(">> Starting ReceiveMessage() pump..."); while (isRunning) { try { simconnect?.ReceiveMessage(); } catch (COMException) { Console.WriteLine(">> Disconnected (COMException in pump)."); break; } await Task.Delay(10); } } catch (COMException ex) { Console.WriteLine($">> COMException during connect: MSFS not found. ({ex.Message} / HRESULT {ex.ErrorCode})"); } catch (Exception ex) { Console.WriteLine($">> General Exception: {ex.Message}"); } Console.WriteLine(">> Test Finished."); } } }
